#!/bin/bash
# HERCOSSNUX NPU - Fase A, Paso 8 (Layer 3, top level): inferencia completa.
# Encadena npu_seq_conv1 y npu_seq_full: imagen 16x16 -> clase.
#   conv1 -> pool1 -> conv2 -> pool2 -> FC -> argmax
#
# NOTA DE TIEMPO: la simulacion de 32 imagenes tarda unos 5 minutos (medido:
# 281 s). Este script corre la verificacion RAPIDA con 8 imagenes y las 2
# mutaciones (~3-4 min en total), imprimiendo progreso en cada etapa.
# Para la inferencia completa de 32 imagenes con firma global, correr despues:
#   bash run_l3_top32.sh
#
# Requiere: ghdl 4.1.0 --std=08, python3. Requiere Pasos 1-3, 6 y 7.
# Linea esperada al final:
# NPU PASO8 OK L3 TOP PASS MUTACIONES 2/2 FAIL
(
set -e
DIR="$HOME/vhdl_repo/IP_Cores/NPU"
for f in model/npu_weights.hex rtl/npu_array.vhd rtl/npu_seq_conv1.vhd rtl/npu_seq_full.vhd; do
  if [ ! -f "$DIR/$f" ]; then
    echo "FALLO: falta $f (corre primero los Pasos 1-3, 6 y 7)"; exit 1
  fi
done
mkdir -p "$DIR/rtl" "$DIR/tb" "$DIR/vec"
base64 -d << "EOF" > "$DIR/rtl/npu_top.vhd"

EOF
base64 -d << "EOF" > "$DIR/tb/tb_npu_top.vhd"

EOF
base64 -d << "EOF" > "$DIR/gen_l3_top.py"

EOF
base64 -d << "EOF" > "$DIR/run_l3_top.sh"

EOF
base64 -d << "EOF" > "$DIR/run_l3_top32.sh"

EOF
chmod +x "$DIR/run_l3_top.sh" "$DIR/run_l3_top32.sh"
cd "$DIR"
bash run_l3_top.sh
)
